    ('A','B'), ('B','C'), ('C','D'), ('D','E'), ('E','F'), ('A','F'), ('B','E')
}
forbidden = {('C','D'), ('D','C')}

def neighbors(node):
    return [v for (u,v) in edges if u == node] + [u for (u,v) in edges if v == node]

# BFS from A to F avoiding C-D
from collections import deque
queue = deque([('A', 0, frozenset())])
visited = {('A', frozenset())}
min_dist = None
while queue:
    node, dist, used = queue.popleft()
    if node == 'F':
        if min_dist is None or dist < min_dist:
            min_dist = dist
        continue
    for nb in neighbors(node):
        edge = (node, nb) if (node, nb) in edges else (nb, node)
        if edge in forbidden:
            continue
        state = (nb, used | {edge})
        if state not in visited:
            visited.add(state)
            queue.append((nb, dist+1, used | {edge}))

print(min_dist)
